// ============================================================
// DigitalCube · Document preparation for the vector KB
// Author: Internal Automation Team
// ------------------------------------------------------------
// Groups blocks by page and builds one document per page
// with its full text + metadata. Metadata is SACRED:
// without source_url, the bot cannot cite the source,
// making the entire project pointless.
// ============================================================

const pages = $('Fetch Notion KB Pages').all();
const blocks = $input.all();

// Index of pages by ID to retrieve title and URL
const pageInfo = {};
for (const p of pages) {
  const pj = p.json;
  const title =
    pj.name ||
    pj.title ||
    (pj.properties?.Name?.title?.[0]?.plain_text) ||
    (pj.properties?.title?.title?.[0]?.plain_text) ||
    'Untitled';
  pageInfo[pj.id] = {
    title,
    url: pj.url || `https://www.notion.so/${String(pj.id).replace(/-/g, '')}`,
    lastEdited: pj.last_edited_time || null,
  };
}

// Extracts plain text from a block (raw or simplified n8n format)
function blockText(b) {
  if (typeof b.content === 'string') return b.content;
  const type = b.type;
  const rt = b[type]?.rich_text || b[type]?.text || [];
  if (Array.isArray(rt)) {
    return rt.map((t) => t.plain_text || t.text?.content || '').join('');
  }
  return '';
}

// Which page each block belongs to (varies by Notion node version)
function blockPageId(b) {
  return b.root_id || b.parent?.page_id || b.parent_id || null;
}

const byPage = {};
for (const item of blocks) {
  const b = item.json;
  const pid = blockPageId(b) || Object.keys(pageInfo)[0];
  const text = blockText(b);
  if (!text || !text.trim()) continue;
  if (!byPage[pid]) byPage[pid] = [];
  byPage[pid].push(text.trim());
}

const output = [];
for (const [pid, texts] of Object.entries(byPage)) {
  const info = pageInfo[pid] || { title: 'Internal Document', url: '', lastEdited: null };
  output.push({
    json: {
      page_content: `# ${info.title}\n\n${texts.join('\n')}`,
      source_title: info.title,
      source_url: info.url,
      last_edited: info.lastEdited,
    },
  });
}

return output;
